#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MOD 998244353

int main() {
    int n, K, i, j, l, c, p, q, r, s, t;
    char S[1000001];

    scanf("%d %d", &n, &K);
    scanf("%s", S);

    for (l = 1; l <= n; l++) {
        p = 1;
        q = 1;
        for (i = 0; i <= n - l; i++) {
            c = 0;
            for (j = 0; j < K; j++) {
                if (i + j * l < n) {
                    c++;
                }
            }
            p = (long long) p * c % MOD;
            q = (long long) q * (c + 1) % MOD;
        }
        r = (long long) p * pow(q, MOD - 2, MOD) % MOD;
        s = (long long) r * pow(q, MOD - 2, MOD) % MOD;
        t = (long long) s * pow(q, MOD - 2, MOD) % MOD;
        printf("%d ", t);
    }
    printf("\n");
    return 0;
}

